allow:
Bash(timeout 5 node --input-type=module <<'EOF' 2>&1 || true
import initSqlJs from 'sql.js';
const SQL = await initSqlJs\(\);
console.log\('sql.js loaded OK'\);
const db = new SQL.Database\(\);
db.exec\('CREATE TABLE test \(id TEXT\)'\);
db.run\('INSERT INTO test VALUES \(?\)', ['hello']\);
const stmt = db.prepare\('SELECT id FROM test'\);
stmt.bind\([]\);
const row = stmt.step\(\) ? stmt.getAsObject\(\) : null;
stmt.free\(\);
console.log\('row:', row\);
EOF)
